query GetCampaignsWithAnalytics($first: Int, $where: CampaignOrderWhereInput, $orderBy: CampaignOrderOrderByInput) {
  campaignOrdersConnection(first: $first, where: $where, orderBy: $orderBy) {
    edges {
      node {
        id
        name
        status
        startDate
        endDate
        budget
        pacingData {
          totalImpressions
          impressionGoal
          pace
          ctr
          roas
        }
        aggregateData {
          id
          completeAttributionSummary
          deviceClicks
        }
      }
    }
    aggregate {
      count
    }
    pageInfo {
      hasNextPage
      endCursor
    }
  }
}

