query GetCampaignReportDetails($first: Int, $where: CampaignOrderWhereInput) {
  campaignOrdersConnection(first: $first, where: $where) {
    edges {
      node {
        id
        name
        status
        reportDetails {
          id
          transaction {
            id
            transactions
            revenue
            spend
            customers
            roas
            byDate {
              date
              transactions
              revenue
              spend
            }
          }
          signups {
            id
            signups
            impressions
            byDate {
              date
              signups
              customers
            }
          }
          sessions {
            id
            sessions
            avgSessionDuration
            pagesPerSession
            byDate {
              date
              sessions
              averageSessionDuration
            }
          }
        }
      }
    }
  }
}
